#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, E, O;
        scanf("%d %d %d", &N, &E, &O);
        int arr[N];
        for (int i = 0; i < N; i++) {
            if (E > 0) {
                arr[i] = 2;
                E--;
            } else {
                arr[i] = 1;
            }
        }
        if (E != 0) {
            printf("-1\n");
        } else {
            for (int i = 0; i < N; i++) {
                printf("%d ", arr[i]);
            }
            printf("\n");
        }
    }
    return 0;
}

